class Solution:
    def numberOfStableArrays(self, zero: int, one: int, limit: int) -> int:
        MOD = 10**9 + 7
        n = zero + one
        dp = [[[0]*(limit+1) for _ in range(one+1)] for _ in range(zero+1)]
        dp[0][0][0] = 1
        for i in range(1, n+1):
            for j in range(min(i, zero)):
                for k in range(min(i, one)):
                    for l in range(1, limit+1):
                        if j < zero:
                            dp[j+1][k][1] = (dp[j+1][k][1] + dp[j][k][l]) % MOD
                        if k < one:
                            dp[j][k+1][1] = (dp[j][k+1][1] + dp[j][k][l]) % MOD
        ans = 0
        for i in range(limit+1):
            ans = (ans + dp[zero][one][i]) % MOD
        return ans
